+  background: var(--color-border-subtle);
+  opacity: 0.5;
+}
+
+.quick-stat__label {
+  font-size: var(--text-2xs);
+  font-weight: var(--font-medium);
+  color: var(--color-text-muted);
+  text-transform: uppercase;
+  letter-spacing: 0.05em;
+}
+
+.quick-stat__value {
+  font-size: var(--text-sm);
+  font-weight: var(--font-semibold);
+  color: var(--color-text);
+  font-variant-numeric: tabular-nums;
+}
+
+.quick-stat__value--highlight {
+  color: var(--color-primary);
+  /* Subtle glow for highlighted values */
+  text-shadow: 0 0 8px rgba(34, 211, 238, 0.3);
+}
+
+/* =============================================================================
+   CONTENT AREA ENHANCEMENTS
+   ============================================================================= */
+
+.main-content-area {
+  display: flex;
+  flex-direction: column;
+  gap: var(--space-4);
+  min-width: 0; /* Prevent overflow */
+  flex: 1;
+}
+
+.viewers-grid {
+  display: grid;
+  grid-template-columns: 1fr;
+  gap: var(--space-4);
+}
+
+/* Desktop: side-by-side viewers */
+@media (min-width: 1024px) {
+  .viewers-grid {
+    grid-template-columns: 1fr 1fr;
+    gap: var(--space-5);
+  }
+}
+
+/* Ultrawide: can fit both viewers larger */
+@media (min-width: 1920px) {
+  .viewers-grid {
+    gap: var(--space-6);
+  }
+}
+
+/* 4K: maximize viewer space */
+@media (min-width: 2560px) {
+  .viewers-grid {
+    gap: var(--space-8);
+  }
+}
+
+/* Single viewer mode - when only showing sequence or 3D */
+.viewers-grid--single {
+  grid-template-columns: 1fr;
+}
+
+@media (min-width: 1024px) {
+  .viewers-grid--single {
+    grid-template-columns: 1fr;
+    max-width: none;
+  }
+}
